// ─── Six-dot menu icon ──────────────────────────────────────────────────────

const DotsIcon = () => (
  <svg width="16" height="24" viewBox="0 0 6 20" fill="none">
    <circle cx="3" cy="3" r="1.4" fill="rgba(190, 240, 168, 0.35)" />
    <circle cx="3" cy="10" r="1.4" fill="rgba(190, 240, 168, 0.35)" />
    <circle cx="3" cy="17" r="1.4" fill="rgba(190, 240, 168, 0.35)" />
  </svg>
);

// ─── Single Card ────────────────────────────────────────────────────────────

interface CardProps {
  title: string;
  stat: string;
  Icon: React.FC;
}

const ScrollCard = ({ title, stat, Icon }: CardProps) => (
  <div
    style={{
      width: "100%",
      padding: "8px",
      borderRadius: 16,
      border: "1px solid rgba(213, 253, 201, 0.08)",
      background: "linear-gradient(135deg, rgb(8, 11, 8) 0%, rgb(12, 16, 12) 100%)",
      display: "flex",
      alignItems: "center",
      boxSizing: "border-box" as const,
      cursor: "default",
      boxShadow: "0 0 20px rgba(190, 240, 168, 0.03), inset 0 1px 0 rgba(213, 253, 201, 0.04)",
      transition: "border-color 0.3s ease, box-shadow 0.3s ease",
    }}
    className="group"
    onMouseEnter={(e) => {
      e.currentTarget.style.borderColor = "rgba(213, 253, 201, 0.15)";
      e.currentTarget.style.boxShadow = "0 0 30px rgba(190, 240, 168, 0.08), inset 0 1px 0 rgba(213, 253, 201, 0.06)";
    }}
    onMouseLeave={(e) => {
      e.currentTarget.style.borderColor = "rgba(213, 253, 201, 0.08)";
      e.currentTarget.style.boxShadow = "0 0 20px rgba(190, 240, 168, 0.03), inset 0 1px 0 rgba(213, 253, 201, 0.04)";
    }}
  >
    {/* Inner lighter box with icon + text + dots */}
    <div
      style={{
        flex: 1,
        minWidth: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        gap: 14,
        padding: "12px 16px",
        borderRadius: 12,
        background: "rgb(14, 18, 14)",
        border: "1px solid rgba(213, 253, 201, 0.04)",
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 14, minWidth: 0 }}>
        <div
          style={{
            width: 44,
            height: 44,
            borderRadius: 9,
            background: "rgba(213, 253, 201, 0.05)",
            border: "1px solid rgba(213, 253, 201, 0.06)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            flexShrink: 0,
          }}
        >
          <Icon />
        </div>
        <div style={{ minWidth: 0 }}>
          <div
            style={{
              fontSize: 15,
              fontWeight: 600,
              letterSpacing: "-0.01em",
              background: "linear-gradient(90deg, rgb(213, 253, 201) 0%, rgb(201, 201, 201) 100%)",
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
              backgroundClip: "text",
              whiteSpace: "nowrap" as const,
              overflow: "hidden",
              textOverflow: "ellipsis",
              lineHeight: 1.4,
            }}
          >
            {title}
          </div>
          <div
            style={{
              fontSize: 11,
              fontWeight: 500,
              letterSpacing: "0.04em",
              textTransform: "uppercase" as const,
              marginTop: 3,
              background: "linear-gradient(90deg, rgb(213, 253, 201) 0%, rgb(201, 201, 201) 100%)",
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
              backgroundClip: "text",
              opacity: 0.7,
              whiteSpace: "nowrap" as const,
              overflow: "hidden",
              textOverflow: "ellipsis",
              lineHeight: 1.3,
            }}
          >
            {stat}
          </div>
        </div>
      </div>
      {/* Dots menu inside inner box */}
      <div style={{ flexShrink: 0, opacity: 0.5 }}>
        <DotsIcon />
      </div>
    </div>
  </div>
);

// ─── Main Vertical Scrolling Carousel ───────────────────────────────────────

const VerticalScrollingCards = () => {
  const GAP = 12;

  // Create a seamless loop by duplicating cards
  // We need enough duplicates to fill the height and scroll smoothly
  const doubledCards = [...cards, ...cards];

  return (
    <div
      className="group"
      style={{
        width: "100%",
        maxWidth: 520,
        height: 1000,
        overflow: "hidden",
        position: "relative",
        maskImage:
          "linear-gradient(to bottom, transparent 0%, black 15%, black 85%, transparent 100%)",
        WebkitMaskImage:
          "linear-gradient(to bottom, transparent 0%, black 15%, black 85%, transparent 100%)",
      }}
    >
      <div
        className="flex flex-col hover:[animation-play-state:paused]"
        style={{
          gap: GAP,
          animation: "marquee-vertical 40s linear infinite",
          willChange: "transform",
        }}
      >
        {doubledCards.map((card, i) => (
          <ScrollCard key={`${card.title}-${i}`} title={card.title} stat={card.stat} Icon={card.Icon} />
        ))}
      </div>
    </div>
  );
};

export default VerticalScrollingCards;
